import React, { useCallback, useEffect, useRef, useState } from 'react';
import './Projects.css';

const PROJECTS = {
  client: [
    { id: 1, driveId: '1kLu1xB-nZ1jgciDCb1dk3HNjhQozzrXQ' },
    { id: 2, driveId: '1TKG_d0NyaAFVMc2LwQOmRQfj6XhKX_C8' },
    { id: 3, driveId: '1R-jHt3l6rJwiYjAgXnZdyn-u5jlky6Z5' },
    { id: 4, driveId: '1TuUcvxbY_VEP_SHWnZ1by2MLNT4AJGrZ' },
    { id: 5, driveId: '1xebUY4lRZGq-R4EfRlMcGNd8KY-SnHhE' },
    { id: 6, driveId: '1KC_0YOuKaEZoAeZPmdNKPV7JC28pJIce' },
    { id: 7, driveId: '1_8tsLwTUPPjwcJEYtpuMjPbH0GOlOsZX' },
    { id: 8, driveId: '1aBefknyW5kPAkexZs5-3JsS2o3XJ8BY0' },
  ],
  personal: [],
  freelance: [],
};

const TABS = [
  { key: 'client', label: 'Client Work' },
  { key: 'personal', label: 'Personal' },
  { key: 'freelance', label: 'Freelance' },
];

const SLICE_COUNT = 8;

function PosterVisual({ showPlay = false, onPlay = null, disabled = false }) {
  return (
    <div className="poster-visual">
      <div className="poster-dots" aria-hidden="true">
        <span className="dot dot-rec" />
        <span className="dot dot-blue" />
      </div>
      <div className="poster-center" aria-hidden="true">
        <span className="poster-rule" />
        <span className="poster-client">CLIENT</span>
        <span className="poster-work">WORK</span>
        <span className="poster-rule" />
      </div>
      <span className="poster-play-hint" aria-hidden="true">{'\u25B6  PLAY'}</span>
      {showPlay && (
        <button
          type="button"
          className="player-play-btn"
          onClick={onPlay}
          aria-label="Play project"
          disabled={disabled}
        >
          <svg viewBox="0 0 24 24" aria-hidden="true">
            <path d="M8 5v14l11-7z" />
          </svg>
        </button>
      )}
    </div>
  );
}

export default function Projects() {
  const [activeTab, setActiveTab] = useState('client');
  const [activeIndex, setActiveIndex] = useState(0);
  const [isPlaying, setIsPlaying] = useState(false);
  const [transitioning, setTransitioning] = useState(false);
  const [glitching, setGlitching] = useState(false);

  const overlayRef = useRef(null);
  const playerWrapperRef = useRef(null);
  const timeoutsRef = useRef([]);

  const currentProjects = PROJECTS[activeTab] || [];
  const activeProject = currentProjects[activeIndex] || null;

  const activeDriveUrl = useMemo(() => {
    if (!activeProject?.driveId) return '';
    return `https://drive.google.com/file/d/${activeProject.driveId}/preview`;
  }, [activeProject]);

  const registerTimeout = useCallback((callback, delay) => {
    const id = setTimeout(callback, delay);
    timeoutsRef.current.push(id);
    return id;
  }, []);

  const clearAllTimeouts = useCallback(() => {
    timeoutsRef.current.forEach((id) => clearTimeout(id));
    timeoutsRef.current = [];
  }, []);

  const triggerOverlaySlices = useCallback(() => {
    if (!overlayRef.current) return;
    overlayRef.current.classList.remove('is-active');
    // Force restart of CSS animation for repeated clicks.
    void overlayRef.current.offsetWidth;
    overlayRef.current.classList.add('is-active');
  }, []);

  const triggerGlitchIn = useCallback(() => {
    if (!playerWrapperRef.current) return;
    playerWrapperRef.current.classList.remove('glitch-in');
    void playerWrapperRef.current.offsetWidth;
    playerWrapperRef.current.classList.add('glitch-in');
    registerTimeout(() => {
      playerWrapperRef.current?.classList.remove('glitch-in');
    }, 420);
  }, [registerTimeout]);

  const handleTabChange = useCallback(
    (tabKey) => {
      if (tabKey === activeTab) return;
      clearAllTimeouts();
      overlayRef.current?.classList.remove('is-active');
      playerWrapperRef.current?.classList.remove('glitch-in');
      setTransitioning(false);
      setGlitching(false);
      setIsPlaying(false);
      setActiveTab(tabKey);
      setActiveIndex(0);
    },
    [activeTab, clearAllTimeouts]
  );

  const handleThumbClick = useCallback(
    (index) => {
      if (index === activeIndex || transitioning || !currentProjects[index]) return;
      clearAllTimeouts();
      setTransitioning(true);
      setIsPlaying(false);
      triggerOverlaySlices();

      registerTimeout(() => {
        setActiveIndex(index);
      }, 200);

      registerTimeout(() => {
        setTransitioning(false);
        overlayRef.current?.classList.remove('is-active');
        triggerGlitchIn();
      }, 650);
    },
    [activeIndex, clearAllTimeouts, currentProjects, registerTimeout, transitioning, triggerGlitchIn, triggerOverlaySlices]
  );

  const handlePlayClick = useCallback(() => {
    if (!activeProject || glitching || transitioning) return;
    clearAllTimeouts();
    setGlitching(true);

    registerTimeout(() => {
      setIsPlaying(true);
      triggerGlitchIn();
    }, 100);

    registerTimeout(() => {
      setGlitching(false);
    }, 600);
  }, [activeProject, clearAllTimeouts, glitching, registerTimeout, transitioning, triggerGlitchIn]);

  useEffect(() => {
    if (!playerWrapperRef.current) return;
    playerWrapperRef.current.dataset.activeIndex = String(activeIndex);
    playerWrapperRef.current.dataset.playing = isPlaying ? '1' : '0';
    playerWrapperRef.current.dataset.glitching = glitching ? '1' : '0';
  }, [activeIndex, isPlaying, glitching]);

  useEffect(() => {
    return () => {
      clearAllTimeouts();
    };
  }, [clearAllTimeouts]);

  return (
    <section className="projects-page">
      <div className="projects-left">
        <div className="projects-tabs" role="tablist" aria-label="Project categories">
          {TABS.map((tab) => (
            <button
              key={tab.key}
              type="button"
              className={`projects-tab ${activeTab === tab.key ? 'is-active' : ''}`}
              onClick={() => handleTabChange(tab.key)}
            >
              {tab.label}
            </button>
          ))}
        </div>

        {currentProjects.length > 0 ? (
          <div className="projects-grid">
            {currentProjects.map((project, index) => (
              <button
                key={project.id}
                type="button"
                className={`thumb-card ${index === activeIndex ? 'is-active' : ''}`}
                onClick={() => handleThumbClick(index)}
              >
                <PosterVisual />
                {index === activeIndex && <span className="thumb-active-accent" aria-hidden="true" />}
              </button>
            ))}
          </div>
        ) : (
          <div className="projects-empty" aria-live="polite">
            <svg viewBox="0 0 24 24" aria-hidden="true">
              <path d="M3 3h7v7H3zM14 3h7v7h-7zM3 14h7v7H3zM17.5 14v2.5H20V19h-2.5v2.5H15V19h-2.5v-2.5H15V14z" />
            </svg>
            <p>Projects coming soon</p>
          </div>
        )}
      </div>

      <aside className="projects-right">
        <div className="preview-row" aria-hidden="true">
          <span className="preview-dot" />
          <span>PREVIEW</span>
        </div>

        <div
          ref={playerWrapperRef}
          className={`player-wrapper ${transitioning ? 'glitch-out' : ''} ${glitching ? 'film-burn' : ''}`}
        >
          {!isPlaying || !activeProject ? (
            <PosterVisual showPlay={!!activeProject} onPlay={handlePlayClick} disabled={!activeProject} />
          ) : (
            <iframe
              className="project-iframe"
              src={activeDriveUrl}
              title={`Project ${activeProject.id}`}
              sandbox="allow-same-origin allow-scripts allow-popups"
              allow="autoplay; encrypted-media"
              allowFullScreen={true}
            />
          )}

          <div ref={overlayRef} className="slice-overlay" aria-hidden="true">
            {Array.from({ length: SLICE_COUNT }).map((_, idx) => (
              <span key={idx} className="slice" style={{ top: `${idx * 12.5}%` }} />
            ))}
          </div>
        </div>

        <div className="player-progress" aria-hidden="true">
          <span className="player-progress-shimmer" />
        </div>
      </aside>
    </section>
  );
}
